import React, { useState, useEffect } from 'react';
import api from './api';
import BudgetForm from './components/BudgetForm';
import InvestmentForm from './components/InvestmentForm';
import AnalyticsDashboard from './components/AnalyticsDashboard';

function App() {
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [user, setUser] = useState(null);
  const [view, setView] = useState('auth');
  const [transactions, setTransactions] = useState([]);
  const [budgets, setBudgets] = useState([]);
  const [investments, setInvestments] = useState([]);

  const register = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post('/auth/register', { 
        name: e.target.name.value, 
        email: e.target.email.value, 
        password: e.target.password.value 
      });
      alert('Registered successfully! Please login.');
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  const login = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post('/auth/login', { 
        email: e.target.email.value, 
        password: e.target.password.value 
      });
      setToken(res.data.token);
      localStorage.setItem('token', res.data.token);
      setUser(res.data.user);
      setView('dashboard');
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  const logout = () => {
    setToken(null);
    setUser(null);
    localStorage.removeItem('token');
    setView('auth');
  };

  const loadTransactions = async () => {
    try {
      const res = await api.get('/transactions');
      setTransactions(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const loadBudgets = async () => {
    try {
      const res = await api.get('/budgets');
      setBudgets(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const loadInvestments = async () => {
    try {
      const res = await api.get('/investments');
      setInvestments(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    if (token) {
      loadTransactions();
      loadBudgets();
      loadInvestments();
    }
  }, [token]);

  // Professional login/register page
  if (view === 'auth' || !token) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-indigo-900 via-purple-900 to-pink-800 flex items-center justify-center p-4 relative overflow-hidden">
        {/* Background decoration */}
        <div className="absolute inset-0">
          <div className="absolute -top-40 -right-40 w-80 h-80 bg-purple-300/20 rounded-full blur-3xl animate-pulse"></div>
          <div className="absolute -bottom-40 -left-40 w-80 h-80 bg-indigo-300/20 rounded-full blur-3xl animate-pulse delay-1000"></div>
        </div>

        <div className="bg-white/90 backdrop-blur-xl rounded-3xl shadow-2xl p-12 max-w-md w-full border border-white/20 relative z-10 transform hover:scale-[1.02] transition-all duration-300">
          {/* Logo */}
          <div className="text-center mb-12">
            <div className="inline-flex items-center px-6 py-3 bg-gradient-to-r from-indigo-500 to-purple-600 rounded-2xl shadow-lg mb-6">
              <svg className="w-8 h-8 text-white mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <span className="text-2xl font-bold text-white">FinTrack</span>
            </div>
            <h1 className="text-4xl font-black bg-gradient-to-r from-gray-800 to-gray-600 bg-clip-text text-transparent mb-2">Welcome Back</h1>
            <p className="text-gray-600 text-lg">Sign in to your personal finance dashboard</p>
          </div>

          {/* Login Form */}
          <form onSubmit={login} className="space-y-6">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Email Address</label>
              <input 
                name="email" 
                type="email" 
                placeholder="Enter your email" 
                className="w-full px-5 py-4 border border-gray-200 rounded-2xl focus:ring-4 focus:ring-indigo-200 focus:border-indigo-500 transition-all duration-300 text-lg placeholder-gray-400 shadow-sm hover:shadow-md" 
                required 
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Password</label>
              <input 
                name="password" 
                type="password" 
                placeholder="Enter your password" 
                className="w-full px-5 py-4 border border-gray-200 rounded-2xl focus:ring-4 focus:ring-indigo-200 focus:border-indigo-500 transition-all duration-300 text-lg placeholder-gray-400 shadow-sm hover:shadow-md" 
                required 
              />
            </div>
            <button 
              type="submit" 
              className="w-full bg-gradient-to-r from-indigo-600 to-purple-600 text-white py-4 px-8 rounded-2xl font-bold text-lg shadow-xl hover:from-indigo-700 hover:to-purple-700 hover:shadow-2xl transform hover:scale-[1.02] hover:-translate-y-0.5 transition-all duration-300"
            >
              Sign In
            </button>
          </form>

          {/* Divider */}
          <div className="relative my-8">
            <div className="absolute inset-0 flex items-center">
              <div className="w-full border-t border-gray-300"></div>
            </div>
            <div className="relative flex justify-center text-sm">
              <span className="px-4 bg-white/90 text-gray-500 font-semibold">New to FinTrack?</span>
            </div>
          </div>

          {/* Register Form */}
          <form onSubmit={register} className="space-y-6">
            <div>
              <input 
                name="name" 
                type="text" 
                placeholder="Full Name" 
                className="w-full px-5 py-4 border border-gray-200 rounded-2xl focus:ring-4 focus:ring-green-200 focus:border-green-500 transition-all duration-300 text-lg placeholder-gray-400 shadow-sm hover:shadow-md" 
                required 
              />
            </div>
            <div>
              <input 
                name="email" 
                type="email" 
                placeholder="Email Address" 
                className="w-full px-5 py-4 border border-gray-200 rounded-2xl focus:ring-4 focus:ring-green-200 focus:border-green-500 transition-all duration-300 text-lg placeholder-gray-400 shadow-sm hover:shadow-md" 
                required 
              />
            </div>
            <div>
              <input 
                name="password" 
                type="password" 
                placeholder="Password (6+ chars)" 
                className="w-full px-5 py-4 border border-gray-200 rounded-2xl focus:ring-4 focus:ring-green-200 focus:border-green-500 transition-all duration-300 text-lg placeholder-gray-400 shadow-sm hover:shadow-md" 
                required 
              />
            </div>
            <button 
              type="submit" 
              className="w-full bg-gradient-to-r from-green-500 to-emerald-600 text-white py-4 px-8 rounded-2xl font-bold text-lg shadow-xl hover:from-green-600 hover:to-emerald-700 hover:shadow-2xl transform hover:scale-[1.02] hover:-translate-y-0.5 transition-all duration-300"
            >
              Create Free Account
            </button>
          </form>

          {/* Footer */}
          <div className="mt-8 pt-8 border-t border-gray-100 text-center">
            <p className="text-xs text-gray-500">Powered by modern finance tech © 2024</p>
          </div>
        </div>
      </div>
    );
  }

  const refreshAll = () => {
    loadTransactions();
    loadBudgets();
    loadInvestments();
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-blue-50">
      {/* Enhanced Nav */}
      <nav className="bg-white/95 backdrop-blur-xl shadow-xl border-b border-gray-200">
        <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">
          <div className="flex items-center space-x-4">
            <div className="w-12 h-12 bg-gradient-to-r from-indigo-500 to-purple-600 rounded-2xl flex items-center justify-center shadow-lg">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08 .402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
            <h1 className="text-2xl font-black bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
              FinTrack
            </h1>
            <span className="text-sm font-semibold bg-blue-100 text-blue-800 px-3 py-1 rounded-full">Premium</span>
          </div>
          <div className="flex items-center space-x-4">
            <nav className="flex space-x-1">
              {['dashboard', 'transactions', 'budgets', 'investments', 'analytics'].map((v) => (
                <button 
                  key={v} 
                  onClick={() => setView(v)} 
                  className={`px-6 py-3 rounded-2xl font-semibold text-sm transition-all duration-300 relative group ${
                    view === v 
                      ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg shadow-blue-500/25 hover:shadow-xl hover:shadow-blue-500/50 transform -translate-y-1' 
                      : 'text-gray-600 hover:text-blue-600 hover:bg-blue-50 border border-transparent hover:border-blue-200'
                  }`}
                >
                  {v.charAt(0).toUpperCase() + v.slice(1)}
                  {view === v && (
                    <div className="absolute -bottom-2 left-1/2 transform -translate-x-1/2 w-20 h-1 bg-gradient-to-r from-blue-400 to-purple-500 rounded-full blur-sm"></div>
                  )}
                </button>
              ))}
            </nav>
            <button 
              onClick={logout} 
              className="bg-gradient-to-r from-red-500 to-pink-600 hover:from-red-600 hover:to-pink-700 text-white px-6 py-3 rounded-2xl font-semibold shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-300"
            >
              Logout
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 py-12">
        <div className="mb-12 flex justify-between items-center">
          <h2 className="text-4xl font-black text-gray-900 capitalize">{view}</h2>
          <button onClick={refreshAll} className="bg-gradient-to-r from-blue-500 to-indigo-600 hover:from-blue-600 hover:to-indigo-700 text-white px-8 py-4 rounded-2xl font-bold shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-300">
            🔄 Refresh Data
          </button>
        </div>

        {view === 'dashboard' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-8 mb-12">
            <div className="bg-white/70 backdrop-blur-xl rounded-3xl shadow-2xl p-10 border border-white/50 hover:shadow-3xl transition-all duration-500">
              <div className="flex items-center mb-6">
                <div className="w-16 h-16 bg-gradient-to-r from-green-400 to-green-500 rounded-2xl flex items-center justify-center shadow-lg mr-4">
                  <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08 .402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                </div>
                <div>
                  <p className="text-sm text-gray-600 font-semibold uppercase tracking-wide">Total Income</p>
                  <p className="text-3xl font-black text-green-600">${transactions.filter(t => t.type === 'income').reduce((sum, t) => sum + parseFloat(t.amount), 0).toFixed(2)}</p>
                </div>
              </div>
            </div>
            {/* Add more stat cards */}
            <AnalyticsDashboard />
          </div>
        )}

        {/* Rest of dashboard content same as before */}
        {view === 'transactions' && (
          <div className="space-y-8">
            <BudgetForm onAdd={refreshAll} />
            <div className="bg-white/70 backdrop-blur-xl rounded-3xl shadow-2xl overflow-hidden border border-white/50">
              <div className="p-8 border-b bg-gradient-to-r from-gray-50 to-blue-50">
                <h3 className="text-2xl font-black text-gray-900 mb-2">Transactions ({transactions.length})</h3>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead className="bg-white/50">
                    <tr>
                      <th className="px-8 py-6 text-left text-lg font-bold text-gray-700">Date</th>
                      <th className="px-8 py-6 text-left text-lg font-bold text-gray-700">Type</th>
                      <th className="px-8 py-6 text-left text-lg font-bold text-gray-700">Category</th>
                      <th className="px-8 py-6 text-right text-lg font-bold text-gray-700">Amount</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                    {transactions.slice().reverse().map((t) => (
                      <tr key={t.id} className="hover:bg-gray-50 transition-colors">
                        <td className="px-8 py-6 text-lg text-gray-900 font-semibold">{t.date}</td>
                        <td className="px-8 py-6">
                          <span className={`px-4 py-2 rounded-full text-sm font-bold ${t.type === 'income' ? 'bg-emerald-100 text-emerald-800 shadow-md' : 'bg-red-100 text-red-800 shadow-md'}`}>
                            {t.type.toUpperCase()}
                          </span>
                        </td>
                        <td className="px-8 py-6 text-lg text-gray-900 capitalize font-medium">{t.category}</td>
                        <td className="px-8 py-6 text-2xl font-black text-right">
                          <span className={t.type === 'income' ? 'text-emerald-600' : 'text-red-600'}>
                            ${parseFloat(t.amount).toFixed(2)}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}

        {/* Similar enhancements for other views */}
        {view === 'budgets' && (
          <div>
            <BudgetForm onAdd={refreshAll} />
            <div className="bg-white/70 backdrop-blur-xl rounded-3xl shadow-2xl overflow-hidden border border-white/50 mt-8">
              {/* Enhanced budgets table */}
            </div>
          </div>
        )}

        {view === 'investments' && (
          <div>
            <InvestmentForm onAdd={refreshAll} />
            <div className="bg-white/70 backdrop-blur-xl rounded-3xl shadow-2xl overflow-hidden border border-white/50 mt-8">
              {/* Enhanced investments table */}
            </div>
          </div>
        )}

        {view === 'analytics' && (
          <AnalyticsDashboard />
        )}
      </main>
    </div>
  );
}

export default App;
